//! Integration tests for the CDQN Runtime and Chronosa Agent execution.
//!
//! This test exercises the full Cognitive Cycle (Dispatcher -> Agents -> Logic)
//! using the sovereign async bus (Condvar-based, zero-CPU-cost waiting).
//! - No sleeps
////! - No timeouts
//! - Uses the dispatcher's wait_for_new_cdu() to coordinate causally

use crate::CdqnRuntime;
use cdqn_cdu::{Cdu, AxiomPayload, World};
use cdqn_hlc::HybridLogicalClock;
use cdqn_cryptocore::hash_sha3_256;
use std::collections::{HashMap, HashSet};
use std::env;
use std::fs;
use std::path::PathBuf;
use std::sync::mpsc;

// ---------- helpers ---------------------------------------------------------

fn create_sovereign_temp_dir() -> PathBuf {
    let dir = env::temp_dir().join(format!("cdqn_test_manifold_{}", std::process::id()));
    fs::create_dir_all(&dir).expect("Failed to create temp dir");
    dir
}

fn cleanup_sovereign_temp_dir(dir: &PathBuf) {
    if dir.exists() {
        fs::remove_dir_all(dir).expect("Failed to clean temp dir");
    }
}

fn create_test_cdu(
    statement: &str,
    r_coordinate: f64,
    genesis_id: &[u8],
    signer: &cdqn_cryptocore::SignerEntity,
) -> Cdu {
    let hlc = HybridLogicalClock::new();
    let node_id = hash_sha3_256(signer.verification_key().as_bytes()).to_vec();

    let payload = AxiomPayload {
        statement: statement.to_string(),
    }
    .into_payload();

    let metadata = cdqn_cdu::Metadata {
        author_node: node_id.clone(),
        context_refs: vec![genesis_id.to_vec()],
        state: "draft".to_string(),
        weight: 1.0,
        r_coordinate,
        world_context: World::UserWorld,
        hlc_timestamp: hlc.new_timestamp(),
        symmetric_counterpart: None,
        validated_worlds: HashSet::new(),
        task_footprints: HashMap::new(),
    };

    let mut cdu = Cdu::new(payload, metadata, &hlc, &node_id);
    cdu.sign(signer, &hlc).expect("CDU signing failed");
    cdu
}

// ---------- test ------------------------------------------------------------

#[test]
fn test_full_cognitive_cycle_verifier() {
    let storage = create_sovereign_temp_dir();

    // deterministic agent-report channels
    let (tx_verifier, rx_verifier) = mpsc::channel::<String>();
    let (tx_evolution, rx_evolution) = mpsc::channel::<String>();

    // runtime with injected channels (agents start immediately and wait on bus)
    let runtime = CdqnRuntime::new_with_test_channels(
        storage.clone(),
        Some(tx_verifier),
        Some(tx_evolution),
    );

    // signer and genesis ID for test CDUs
    let test_signer = cdqn_cryptocore::SignerEntity::new_random("TestNodeSigner");
    let genesis_id = runtime.manifold.genesis_id.clone();

    // Observe the bus causally using its zero-CPU wait
    let dispatcher = runtime.dispatcher.clone_for_agent();
    let start_len = dispatcher.log_len();

    // 1) publish first CDU, then wait causally for bus length to advance
    let valid = create_test_cdu("Valid Axiom", 2.5, &genesis_id, &test_signer);
    runtime
        .dispatcher
        .publish(valid)
        .expect("publish(valid) failed");

    // This returns immediately if length already advanced; otherwise waits on Condvar.
    dispatcher
        .wait_for_new_cdu(start_len)
        .expect("wait_for_new_cdu after valid publish failed");

    // 2) publish second CDU (contradiction), then wait causally again
    let contradict = create_test_cdu("Contradictory Fact", 0.5, &genesis_id, &test_signer);
    runtime
        .dispatcher
        .publish(contradict)
        .expect("publish(contradictory) failed");

    dispatcher
        .wait_for_new_cdu(start_len + 1)
        .expect("wait_for_new_cdu after contradictory publish failed");

    // 3) collect verifier results (expect exactly 2) — blocking recv uses OS wait (no busy-loop)
    let v1 = rx_verifier.recv().expect("no verifier msg #1");
    let v2 = rx_verifier.recv().expect("no verifier msg #2");
    let verifier_outcomes = vec![v1, v2];

    // 4) collect evolution result (expect exactly 1)
    let evo = rx_evolution.recv().expect("no evolution msg");

    // Logs for CI diagnosis
    println!("\n=== VERIFICATION RESULTS SUMMARY ===");
    println!("Verifier Result 1: {}", verifier_outcomes[0]);
    println!("Verifier Result 2: {}", verifier_outcomes[1]);
    println!("Evolution Result: {}", evo);
    println!("=====================================\n");

    // Assertions
    assert_eq!(
        verifier_outcomes.len(),
        2,
        "Expected 2 verifier results, got {}",
        verifier_outcomes.len()
    );

    assert!(
        verifier_outcomes
            .iter()
            .any(|s| s.contains("VERIFIED (RWorld: 2.5)")),
        "Valid CDU not verified: {:?}",
        verifier_outcomes
    );

    assert!(
        verifier_outcomes
            .iter()
            .any(|s| s.contains("CONTRADICTION (RWorld: 0.5)")),
        "Contradictory CDU not detected: {:?}",
        verifier_outcomes
    );

    assert!(
        evo.contains("RESOLVED: Resolved with Hash:"),
        "Evolution agent did not resolve contradiction: {}",
        evo
    );

    cleanup_sovereign_temp_dir(&storage);
}
